const html = $input.first().json.data || '';
const staticData = $getWorkflowStaticData('global');

// Find the <li> that contains the DSE entry and check if CET Cell has added a real link.
// Currently the DSE item is a plain <span> with no href.
// When the schedule is published, CET Cell wraps it in <a href="...">.
// We skip generic/RSS hrefs like /feed that appear on all pages.

const liPattern = /<li[^>]*>([\s\S]*?)<\/li>/gi;
let liMatch;
let dseLink = null;
let dseLinkFound = false;

while ((liMatch = liPattern.exec(html)) !== null) {
  const liContent = liMatch[1];
  if (/Direct\s+second\s+[Yy]ear/i.test(liContent)) {
    const hrefMatch = /href=["']([^"']+)["']/i.exec(liContent);
    if (hrefMatch) {
      const href = hrefMatch[1];
      const isGeneric = href.includes('/feed') || href.includes('?feed') || href === '/' || href === '#' || href === '';
      if (!isGeneric) {
        dseLink = href.startsWith('http') ? href : 'https://cetcell.mahacet.org' + href;
        dseLinkFound = true;
      }
    }
    break;
  }
}

const lastDseLinkFound = staticData.dseLinkFound;
staticData.dseLinkFound = dseLinkFound;

if (dseLinkFound === lastDseLinkFound || !dseLinkFound) {
  return [];
}

return [{ json: { dseLink, pageUrl: 'https://cetcell.mahacet.org/cap-_2026-27/' } }];

const item = $input.first().json;
const lines = [
  '\ud83c\udf89 <b>DSE 2026-27 Schedule is LIVE!</b>',
  '',
  'CET Cell has published the Direct Second Year Engineering admission schedule.',
  '',
  '\ud83d\udd17 <a href="' + item.dseLink + '">Open DSE Schedule</a>',
  '',
  '\ud83d\udccc <a href="' + item.pageUrl + '">CAP 2026-27 Page</a>'
];
return [{ json: { text: lines.join('\\n') } }];
